            '--vibe-badge-bg': 'rgba(107, 127, 163, 0.25)',
            '--vibe-badge-text': '#c9d4e3',
            '--vibe-glow': 'rgba(107, 127, 163, 0.18)',
        },
    },
};

function getVibeKey(hour) {
    if (hour >= 5 && hour <= 10) return 'morning';
    if (hour >= 11 && hour <= 15) return 'midday';
    if (hour >= 16 && hour <= 19) return 'golden';
    if (hour >= 20 && hour <= 22) return 'twilight';
    return 'moonlight';
}

export function getVibeForTimestamp(created_at) {
    if (!created_at) return null;
    const hour = new Date(created_at).getHours();
    const key = getVibeKey(hour);
    const config = VIBE_CONFIG[key];
    return { key, ...config };
}

export default function useVibeTheme(created_at) {
    return getVibeForTimestamp(created_at);
}

