    --vibe-glow: rgba(107, 127, 163, 0.1);
}

[data-theme="dark"] .vibe-moonlight-stars {
    opacity: 0.2;
}

/* ── Mobile ── */
@media (max-width: 480px) {
    .vibe-badge {
